// shadcn
import { Button } from "@/components/ui/button";

// constants
const testimonials = [
  {
    name: "Joseph William",
    role: "Manager at Apple",
    text: "At half-past eight the door opened, the policeman appeared, and requesting them to follow him, led the way to an adjoining hall."
  },
  {
    name: "Shirley Hoe",
    role: "Manager at Apple",
    text: "At half-past eight the door opened, the policeman appeared, and requesting them to follow him, led the way to an adjoining hall."
  },
  {
    name: "Joseph William",
    role: "Manager at Apple",
    text: "At half-past eight the door opened, the policeman appeared, and requesting them to follow him, led the way to an adjoining hall."
  }
];

//  ------------------------------ | TESTIMONIAL 2 | ------------------------------  //

export default function Testimonial2() {
  return (
    <section className="py-24">
      <div className="container mx-auto px-6">
        <div className="grid grid-cols-12 gap-8">
          {testimonials.map((t, i) => (
            <div
              key={i}
              className="col-span-12 md:col-span-4 flex flex-col items-start gap-2"
            >
              <h5 className="mt-2 mb-1">{t.name}</h5>
              <h6 className="mb-2">{t.role}</h6>
              <p className="text-muted-foreground mb-6 max-w-xs">{t.text}</p>
            </div>
          ))}
        </div>
        <div className="flex justify-center mt-8">
          <Button
            variant="outline"
            className="text-primary outline-primary"
            size="lg"
          >
            View All
          </Button>
        </div>
      </div>
    </section>
  );
}
